-- Enrichment marathon batch: Authgear, AuthPass, Authress, Authy, Autodesk, AutoLocalise, Autopilot (now Ortto), Avail

-- ── Authgear ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Authgear is an open-source customer identity and access management (CIAM) platform that gives developers passkeys, passwordless login, single sign-on, and multi-factor authentication as a ready-to-use service, deployable as managed cloud or self-hosted software.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid Cloud plans start at $50/month; self-hosted Authgear ONCE starts at $299 one-time$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$small team (exact headcount not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$Hong Kong, with additional offices in Taiwan, the UK, Canada, and the US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Authgear Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Authgear is an open-source CIAM platform with passkeys, SSO and MFA. Compare 2026 pricing, features, pros and cons, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Authgear is an open-source customer identity and access management (CIAM) platform built for developers who need to add authentication and authorization to web and mobile applications without building it from scratch. It is the flagship product of SkyMakers Digital Group (previously operating under the Oursky name), a bootstrapped, profitable software studio that has served enterprise and startup clients since 2009; the Authgear product itself appears to have launched around 2020 based on its public social and developer presence. Authgear is not known to have raised venture funding, and the company describes itself as deliberately independent of external investors. The platform offers passwordless and passkey login, biometric authentication, single sign-on (SSO) via SAML and OIDC, multi-factor authentication (SMS, WhatsApp, TOTP, and authenticator apps), pre-built login UI widgets, bot protection, and detailed audit logs. It can be consumed as Authgear Cloud, a fully managed SaaS offering, or self-hosted via Authgear ONCE, a one-time-purchase license that includes two years of updates. Pricing is transparent and usage-based on monthly active users (MAUs) and messaging volume: a free tier supports unlimited MAUs with limited SMS/WhatsApp messages and up to two applications, a Developers plan starts at fifty dollars per month, and a Business plan starts at five hundred dollars per month for higher usage and support tiers; Enterprise pricing is custom. Authgear holds ISO 27001 and SOC 2 Type II compliance certifications and runs on Microsoft Azure and Google Cloud infrastructure, with publicly referenced customers including Hong Kong MTR, Bupa, and Outback Steakhouse. Its target audience is engineering teams at startups and mid-market companies that want an Auth0, Firebase Authentication, or Clerk alternative with either a cloud-hosted option or full self-hosted control of their identity data, particularly teams that value open-source transparency and predictable pricing over the larger ecosystem and brand recognition of incumbents like Auth0 (Okta) or Ping Identity. Compared to those larger CIAM vendors, Authgear is smaller and has a less extensive third-party integration marketplace, but it offers a more generous free tier, simpler pricing, and the option to self-host for organizations with data residency or compliance requirements.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7';

