-- ── AuthPass ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AuthPass is a free, open-source, cross-platform password manager built with Flutter that is fully compatible with KeePass KDBX 3 and KDBX 4 database files.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$independent open-source project maintained by its creator and community contributors$q$, company_size),
  headquarters = COALESCE($q$Austria (creator's location); distributed open-source contributor community$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AuthPass Review 2026: Free KeePass-Compatible Manager$q$, seo_title),
  seo_meta_description = COALESCE($q$AuthPass is a free open-source password manager built with Flutter, compatible with KeePass KDBX files. See features, pricing, and pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AuthPass is a free, open-source, cross-platform password manager built with the Flutter framework, first released around September 2019 by Herbert Poul, a freelance mobile and web developer based in Austria. The project is now maintained by Poul along with a group of open-source community contributors on GitHub, and it is distributed under the GPL-3.0 license. AuthPass is not a venture-backed company; there is no public record of institutional funding, and it operates as an independent open-source project rather than a commercial entity with disclosed revenue or headcount. Its defining feature is full compatibility with KeePass database files (both KDBX 3 and KDBX 4 formats), which lets users who already store passwords in KeePass, KeePassXC, or similar tools open and edit the same encrypted database from AuthPass on any supported platform. The app runs on Windows, macOS, Linux, Android, and iOS, plus a web-based edition that works in any modern browser, and it supports biometric unlock (fingerprint or face recognition) backed by the operating system's secure keystore or keychain. For syncing, AuthPass relies on existing cloud storage providers such as Google Drive, Dropbox, and WebDAV-compatible services like Nextcloud and ownCloud, rather than operating its own proprietary sync backend. Because the core app and its source code are free and open, AuthPass has no subscription tiers or paid plans in the traditional sense; its pricing model is effectively free and open-source software, with the project sustained through community contributions and, at various points, an associated AuthPass Cloud sync offering. Its target audience is privacy-conscious individuals and technical users who want a self-controlled, standards-based password manager rather than a closed-source SaaS vault, and specifically people already invested in the KeePass ecosystem who want a modern, Flutter-based client. Compared to commercial alternatives like 1Password, LastPass, or Bitwarden, AuthPass trades built-in cloud sync and dedicated customer support for open-source transparency, no subscription cost, and direct compatibility with the widely used KDBX file format.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cb5c1462-f100-411d-80a6-5e607484818f';

