-- ── Authress ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Authress is a developer-focused login and access control API that combines authentication with fine-grained, resource-based authorization, billed on a pay-per-call basis.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$$0.0012 per API call after the first 1,000 free calls per month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$small team (exact headcount not publicly disclosed); described as an unfunded, independently operated company$q$, company_size),
  headquarters = COALESCE($q$Winterthur, Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Authress Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Authress is a pay-per-call authentication and authorization API. See 2026 pricing, features, pros and cons, and how it compares to Auth0.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Authress is a developer-focused API that combines user authentication with fine-grained, resource-based authorization, allowing engineering teams to manage both who a user is and exactly what they are allowed to access from a single service. It is operated by Rhosys AG and, according to third-party company databases, was founded in 2018 by Dorota Parad and is headquartered in Winterthur, Switzerland; it is described as an unfunded, independently operated company with no disclosed institutional investment. Authress differentiates itself from many identity providers by emphasizing authorization as a first-class concern rather than an afterthought: it issues JWTs, manages user sign-up and sign-in flows, and layers on granular, resource-level access control so that permissions can be scoped to specific records or objects rather than just broad roles. Supported capabilities include unlimited single sign-on connections across SAML, OAuth, and OIDC, social login, machine-to-machine tokens, enterprise sign-up and invitation flows, and a claimed 99.995 percent availability SLA. Pricing is usage-based and unusually transparent for the identity category: Authress charges 0.0012 US dollars per billable authentication or authorization API call, with the first 1,000 calls each month free, and the company markets this as having no enterprise tax, meaning all customers get the same feature set regardless of spend rather than gating capabilities like SSO or advanced permissions behind higher-priced tiers. There are no separate named pricing plans beyond this single pay-per-use structure. Authress's target audience is engineering teams, particularly at startups and mid-sized software companies, that need both authentication and granular authorization in one integration and want to avoid the cost escalation and feature-gating common with larger identity platforms. It is most directly compared to Auth0, Okta, and similar CIAM vendors, but its narrower focus on combining login with resource-based access control also puts it in the same conversation as dedicated authorization services. Because Authress is a smaller, independently run company, prospective users should weigh its transparent pricing and authorization-first design against the larger support organizations, integration marketplaces, and enterprise track records of bigger competitors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ce7d7abb-965e-47fa-a6cd-0327c7df9079';

