-- ── Authy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Authy is a two-factor authentication (2FA) mobile app owned by Twilio; its desktop apps were discontinued in 2024, and Twilio has scaled back investment in the consumer product while steering developers toward its Twilio Verify API.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$operated as a product within Twilio, a public company with over 5,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California (Twilio headquarters); Authy was originally founded in Colombia before relocating$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Authy Status in 2026: Is It Still Supported? Full Review$q$, seo_title),
  seo_meta_description = COALESCE($q$Authy is Twilio's 2FA app. See its 2026 status after the desktop app shutdown, current features, pricing, and the best alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Authy is a two-factor authentication (2FA) mobile application originally founded around 2011 to 2012, reportedly starting in Colombia before relocating to California, by Daniel Palacio. It raised early seed funding, including backing from Y Combinator, before Twilio acquired it in February 2015 for an undisclosed amount; financial terms of the acquisition were never publicly released. Authy generates time-based one-time passcodes (TOTP) and supports push-based authentication, offering features such as encrypted cloud backup of tokens, multi-device synchronization, and offline code generation, and it has historically been offered free to consumers while Twilio separately monetized the underlying Authy API and, later, its Verify API for business customers. As of this writing, Authy's status has changed materially since its early years: Twilio discontinued the Authy desktop applications for Windows, macOS, and Linux, with end-of-life on March 19, 2024, forcing all desktop users to migrate to the mobile-only app. Twilio has publicly stated it is streamlining focus toward higher-demand products, and industry coverage describes Authy's mobile app as being in a reduced-investment or maintenance-oriented state, with Twilio directing developers toward its separate Verify API rather than the legacy Authy API for new integrations. As of the time of this research, Twilio has stated it intends to continue supporting the Authy mobile apps for existing users and as a consumer 2FA option, but no fixed long-term roadmap or feature-development commitment has been publicly confirmed, and security commentators increasingly recommend evaluating alternatives such as Aegis, Ente Auth, 2FAS, or Microsoft Authenticator, particularly given Authy's historical lack of an official token-export feature. Given this trajectory, prospective users should treat Authy as a legacy consumer 2FA app that remains functional but is not clearly under active feature development, rather than as a fully deprecated or fully thriving product; readers should verify Authy's current app store availability and any new Twilio announcements before relying on it for new 2FA setups.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e1766994-68c6-4c8b-afda-889f3aaad6f4';

