-- ── Autodesk ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Autodesk is a large public software company that makes design and engineering applications, including AutoCAD, Revit, Maya, and Fusion, used across architecture, engineering, construction, manufacturing, and media and entertainment.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$Varies by product; Fusion starts free for personal use, with paid subscriptions such as Revit at roughly $2,915 per year for a single named-user license$q$, starting_price),
  founded_year = COALESCE(1982, founded_year),
  company_size = COALESCE($q$approximately 15,000+ employees (publicly traded, NASDAQ: ADSK)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Autodesk Review 2026: Products, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Autodesk makes AutoCAD, Revit, Maya and Fusion. See 2026 pricing, key products, pros and cons for architecture, engineering and design teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Autodesk is a large, publicly traded American software company (NASDAQ: ADSK) that develops design, engineering, and creative software used across architecture, engineering, construction (AEC), manufacturing, and media and entertainment industries. It was founded in April 1982 by John Walker, Daniel Drake, and a group of other programmers with an initial investment of roughly sixty thousand dollars; the company's first major product, AutoCAD, released in 1982, became one of the earliest widely adopted computer-aided design (CAD) programs for personal computers. Autodesk was headquartered in San Rafael, California, from 1994 until 2022, when it moved its official headquarters to San Francisco. As a mature public company, Autodesk does not disclose venture funding figures since it has been publicly traded since 1985; recent public filings put annual revenue in the range of several billion dollars (approximately 6.78 billion dollars, per third-party financial trackers) and employee headcount at roughly 15,000 to 15,300, though the company announced workforce reductions of about seven percent (roughly 1,000 roles) as part of a 2026 restructuring. Autodesk's product portfolio spans multiple flagship applications rather than a single tool: AutoCAD for general-purpose 2D and 3D drafting, Revit for building information modeling (BIM) in architecture and construction, Civil 3D for civil engineering, Maya and 3ds Max for 3D animation and visual effects used heavily in film and games, and Fusion (formerly Fusion 360) for cloud-based mechanical design, simulation, and manufacturing. Nearly all products are sold via subscription, typically billed monthly, annually, or on multi-year terms, with bundled offerings like the Architecture, Engineering and Construction (AEC) Collection combining several tools at a discount versus buying them individually. Fusion offers a limited free tier for personal, non-commercial use. Autodesk's target audience ranges from individual freelance designers and students (who can access free educational licenses) up to large enterprise engineering, construction, and media production companies. Its main competitors vary by product line and include Dassault Systemes (SolidWorks, CATIA), Bentley Systems, Trimble (SketchUp), PTC, and Blender (as a free alternative for 3D animation), with Autodesk generally positioned as the entrenched, feature-complete incumbent across most of the categories it competes in.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '11674814-c70f-44c9-ba68-d6bf1db1e289';

