  short_description = COALESCE($q$Autopilot was a visual marketing automation platform that has since been fully rebranded as Ortto; the Autopilot name and autopilothq.com domain are retired, and the product now operates under the Ortto brand.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
