  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Now operates as Ortto; historical Autopilot team size not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Historically San Francisco, California and Sydney, Australia; now operates as Ortto$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Autopilot Marketing Automation: What Happened, Now Ortto$q$, seo_title),
  seo_meta_description = COALESCE($q$Autopilot marketing automation was rebranded as Ortto in 2022. See its history, what changed, and where to find the product today.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Autopilot was a visual, drag-and-drop marketing automation platform originally built to help marketing teams design customer journeys, email campaigns, and lead-nurturing workflows without writing code. The company was founded around 2011 and built a customer base using a distinctive canvas-style journey builder. In 2021 the company began rebuilding its product with expanded customer data and analytics capabilities beyond marketing automation alone, releasing the rebuilt platform in beta that year, and in March 2022 it completed a full rebrand from Autopilot to Ortto, retiring the Autopilot name and the autopilothq.com domain, which now redirects to Ortto's site. According to the company's own public explanation, the rebrand reflected an evolution beyond the original journey-builder product into a broader customer data, messaging, and analytics platform, rather than a shutdown or asset sale. Available public sources for this research did not surface a confirmed acquisition of Autopilot by Aurea or ESW Capital; while Aurea and its affiliate ESW Capital are known for acquiring and operating a portfolio of enterprise software brands (such as Jive Software), no documentation was found directly linking Autopilot or Ortto to that portfolio, so any claim of an Aurea or ESW Capital acquisition should be treated as unverified rather than confirmed fact. What is verifiable is that Autopilot no longer exists as an actively sold, independently branded product: its technology, customer base, and go-to-market direction continued forward under the Ortto brand starting in 2022, and prospective buyers researching Autopilot today should evaluate Ortto instead, since that is where current pricing, features, and support are found. Because Autopilot itself is discontinued as a brand, this profile should be read as historical and transitional context rather than a live product recommendation; for current features and pricing, readers should consult Ortto directly rather than relying on legacy Autopilot marketing materials, which may be outdated or no longer maintained.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a7e05556-33fe-45dc-becd-a33082027c3f';

