-- ── Avail ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Avail is a property management platform for independent landlords, offering free and paid tools for listing rentals, screening tenants, signing leases, and collecting rent; it operates as part of the Realtor.com network following its 2020 acquisition by Move, Inc.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Unlimited plan); paid Unlimited Plus plan is $9 per unit per month$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$operates as part of Move, Inc. (Realtor.com), a News Corp subsidiary$q$, company_size),
  headquarters = COALESCE($q$Chicago, Illinois, United States (as part of the Realtor.com network)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Avail Review 2026: Pricing, Features for DIY Landlords$q$, seo_title),
  seo_meta_description = COALESCE($q$Avail is Realtor.com's landlord software for listing, screening, leasing and rent collection. See 2026 pricing, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Avail is a property management platform built for independent, do-it-yourself landlords who typically own between one and fifty rental units. It began as Rentalutions, a Chicago-based startup founded around 2013, before rebranding to Avail. On December 15, 2020, Move, Inc., the operator of Realtor.com and a subsidiary of News Corp, acquired Avail; the acquisition's financial terms were not publicly disclosed. Following the deal, Avail continued operating under its own brand rather than being absorbed or discontinued, and it is now marketed as 'Avail, by Realtor.com,' reflecting its position within the larger Realtor.com rental products ecosystem while retaining its distinct product identity. In 2026, Avail began migrating its web presence from the avail.co domain to avail.com to better align with its Realtor.com branding, with the old domain redirecting automatically. The platform provides landlords with tools to list rental properties across multiple listing sites (Avail advertises distribution to roughly 19 rental listing sites), screen prospective tenants with reports powered by TransUnion (including credit, criminal background, and eviction history), generate state- and city-specific digital lease agreements, collect rent online, and track maintenance requests through a tenant portal. Avail's pricing follows a freemium model: the Unlimited plan is free and includes core listing, screening, leasing, and rent collection features, while the paid Unlimited Plus plan costs nine dollars per unit per month and adds features such as faster rent payouts (FastPay), waived ACH transfer fees, customizable lease templates, a brandable property website, and priority customer support; tenants may separately pay for screening reports and a card payment processing fee of 3.5 percent applies on both plans. Avail's target audience is small-scale, independent landlords who want professional-grade tools without the cost or complexity of full-service property management companies. It competes with platforms such as TurboTenant, Zillow Rental Manager, RentRedi, and Buildium (the last more oriented toward larger portfolios), differentiating itself through its integration with the high-traffic Realtor.com listing network and its ownership by a major, publicly traded media and real estate company.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '69678cd0-36bc-465c-ad49-76349776fb26';

