INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Passwordless and passkey login$q$, $q$Lets end users sign in with passkeys, biometrics, or magic links instead of passwords.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Enterprise SSO$q$, $q$Supports SAML and OIDC single sign-on for connecting to enterprise identity providers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Multi-factor authentication$q$, $q$Adds SMS, WhatsApp, TOTP, and authenticator app-based second factors to any login flow.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Pre-built login UI$q$, $q$Ships customizable, hosted sign-up and sign-in screens so teams do not have to design their own.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Self-hosted or cloud deployment$q$, $q$Available as managed Authgear Cloud or as a self-hosted Authgear ONCE package for data residency needs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Audit logs and compliance$q$, $q$Provides detailed audit trails and holds ISO 27001 and SOC 2 Type II certifications.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Bot and credential-stuffing protection$q$, $q$Includes safeguards against automated abuse of sign-up and login endpoints.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Role-based access control$q$, $q$Allows fine-grained permissions and roles to be attached to user accounts.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Open-source codebase with a self-hosted option for full data control$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Generous free tier with unlimited monthly active users$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Transparent, predictable pricing compared to larger CIAM vendors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Bootstrapped and profitable, reducing pressure from investor-driven roadmap changes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$ISO 27001 and SOC 2 Type II compliance for regulated industries$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Smaller ecosystem and integration marketplace than Auth0 or Okta$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Self-hosting requires in-house DevOps and infrastructure expertise$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Limited public information about company financials and team size$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Fewer publicly documented enterprise case studies than larger competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$SMS/WhatsApp messaging costs add up on higher-volume plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$What is Authgear used for$q$, $q$Authgear is used by development teams to add login, sign-up, and account security to web and mobile applications without building authentication infrastructure from scratch.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Is Authgear open source$q$, $q$Yes, Authgear's core server is open source, and it can also be self-hosted through the Authgear ONCE package.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$How much does Authgear cost$q$, $q$Authgear Cloud has a free plan, paid plans starting at fifty dollars per month, and custom Enterprise pricing; the self-hosted Authgear ONCE option starts at a one-time fee of two hundred ninety-nine dollars.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Does Authgear support passkeys$q$, $q$Yes, Authgear supports passkeys and biometric login alongside traditional password and social login options.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Who owns Authgear$q$, $q$Authgear is built and operated by SkyMakers Digital Group, a bootstrapped software studio with offices in Hong Kong, Taiwan, the UK, Canada, and the US.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Is Authgear a good Auth0 alternative$q$, $q$Authgear is commonly positioned as an Auth0 or Firebase Authentication alternative, offering similar core authentication features with simpler pricing and a self-hosting option.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Can Authgear handle enterprise SSO$q$, $q$Yes, Authgear supports SAML and OIDC-based single sign-on for connecting business applications to enterprise identity providers.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Does Authgear have a free tier$q$, $q$Yes, Authgear Cloud offers a free plan with unlimited monthly active users and limited SMS or WhatsApp messaging.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Startup adding login to a new app$q$, $q$Early-stage teams use Authgear's free tier to launch passwordless and social login quickly without dedicating engineering time to building auth.$q$, $q$Startup engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Regulated company needing self-hosted identity$q$, $q$Organizations with data residency or compliance requirements deploy Authgear ONCE on their own infrastructure while keeping the same feature set as the cloud product.$q$, $q$Regulated industries such as healthcare and finance$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Enterprise consolidating customer logins$q$, $q$Mid-market and enterprise companies use Authgear's SSO and MFA features to unify login across multiple customer-facing applications.$q$, $q$Enterprise IT and identity teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Cloud Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["Unlimited monthly active users","100 SMS/WhatsApp messages per month","2 applications","2 project members","1 day log retention","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Cloud Developers$q$, $q$$50/month$q$, $q$monthly$q$, NULL, $q$["Unlimited monthly active users","Metered SMS/WhatsApp pricing","2 applications","2 project members","Priority email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Cloud Business$q$, $q$$500/month$q$, $q$monthly$q$, NULL, $q$["25,000 monthly active users included","5 applications","5 project members","60 day log retention","Dedicated Slack channel"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Cloud Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Volume MAU discounts","Data residency options","Custom SMS gateway","Dedicated account manager"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$Authgear ONCE (self-hosted)$q$, $q$$299 one-time$q$, $q$one-time$q$, NULL, $q$["Unlimited monthly active users","Unlimited applications","120 day log retention","2 years of software updates"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$overview$q$, $q$What Is Authgear$q$, 2, ARRAY[$q$Authgear is an open-source customer identity and access management (CIAM) platform designed to give developers a plug-and-play way to handle sign-up, login, and account security for consumer-facing web and mobile applications. Rather than building authentication logic in-house, teams integrate Authgear's SDKs and pre-built UI to get passwordless login, passkeys, social login, and multi-factor authentication out of the box.$q$, $q$The product is built by SkyMakers Digital Group, a software studio with roots going back to 2009 and offices spanning Hong Kong, Taiwan, the UK, Canada, and the US. The company positions itself as bootstrapped and profitable, explicitly contrasting itself with venture-backed competitors that it says must eventually prioritize growth and valuation over long-term product stability.$q$, $q$Authgear can be deployed two ways: as Authgear Cloud, a fully managed SaaS product, or as Authgear ONCE, a self-hosted package sold as a one-time license so organizations that need to keep identity data on their own infrastructure can still use the same core platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Authgear's core feature set covers the full authentication lifecycle: passwordless and passkey-based login, biometric authentication on supported devices, social login, and traditional email or phone plus password flows.$q$, $q$For organizations with more complex identity needs, it supports enterprise single sign-on through SAML and OIDC, multi-factor authentication via SMS, WhatsApp, TOTP, and authenticator apps, role- and permission-based access control, and bot or credential-stuffing protection.$q$, $q$Operational features include pre-built, customizable login UI widgets so teams do not need to build their own auth screens, audit logs for compliance reviews, and dashboards for managing applications, project members, and usage across environments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Authgear Cloud offers a free plan with unlimited monthly active users, up to 100 SMS or WhatsApp messages per month, and support for two applications and two project members, making it usable for early-stage products at no cost.$q$, $q$The paid Developers plan starts at fifty dollars per month and adds metered SMS/WhatsApp pricing and priority email support, while the Business plan starts at five hundred dollars per month for twenty-five thousand included MAUs, five applications, longer log retention, and a dedicated Slack channel. Enterprise pricing is custom and adds data residency options, custom SMS gateways, and dedicated support.$q$, $q$Organizations that prefer to self-host can instead buy Authgear ONCE for a flat two hundred ninety-nine dollar one-time fee, which includes unlimited applications and MAUs plus two years of software updates; an Enterprise ONCE tier with high-availability support is available at custom pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5fa95c96-0cfd-470a-beb9-f4dd6e02c8a7', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$KeePass KDBX compatibility$q$, $q$Opens and saves standard KDBX 3 and KDBX 4 database files used by KeePass and KeePassXC.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Cross-platform Flutter app$q$, $q$Runs on Windows, macOS, Linux, Android, iOS, and the web from a single codebase.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Biometric unlock$q$, $q$Uses the device keystore or keychain to unlock vaults with fingerprint or face recognition.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Cloud storage sync$q$, $q$Syncs vault files via Google Drive, Dropbox, or WebDAV services like Nextcloud.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Open-source codebase$q$, $q$Source code is publicly available on GitHub under the GPL-3.0 license.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Password generator$q$, $q$Built-in generator for creating strong, random passwords for new entries.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Key file support$q$, $q$Supports an optional key file in addition to the master password for extra vault security.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Completely free with no subscription cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Open-source code that can be independently audited$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Full compatibility with the widely used KeePass KDBX format$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Works across desktop, mobile, and web on a single vault$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$No vendor lock-in since users control their own database file and storage$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$No proprietary built-in cloud sync, requiring a third-party storage account$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Relies on volunteer maintenance rather than a dedicated support team$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Less polished enterprise features compared to commercial password managers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Smaller community and slower feature velocity than large funded competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Is AuthPass free$q$, $q$Yes, AuthPass is completely free and open-source, with no subscription or license fee for the core application.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Is AuthPass compatible with KeePass$q$, $q$Yes, AuthPass reads and writes standard KeePass KDBX 3 and KDBX 4 database files, so it can open vaults created in KeePass or KeePassXC.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Who makes AuthPass$q$, $q$AuthPass was created by Herbert Poul, a freelance developer based in Austria, and is maintained with community contributions on GitHub.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Does AuthPass sync across devices$q$, $q$AuthPass does not run its own sync service; instead it syncs vault files through connected cloud storage such as Google Drive, Dropbox, or WebDAV.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$What platforms does AuthPass support$q$, $q$AuthPass runs on Windows, macOS, Linux, Android, iOS, and in the browser through a web edition.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Is AuthPass open source$q$, $q$Yes, AuthPass's source code is publicly hosted on GitHub and distributed under the GPL-3.0 license.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Can AuthPass use biometric login$q$, $q$Yes, on supported devices AuthPass can store the master password in the secure keystore or keychain and unlock via fingerprint or face recognition.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Existing KeePass users switching clients$q$, $q$Users with an existing KDBX vault can open it directly in AuthPass without migrating or converting data.$q$, $q$KeePass and KeePassXC users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Privacy-conscious individuals avoiding subscriptions$q$, $q$People who want a password manager without an ongoing subscription fee or a closed proprietary vault format use AuthPass as a free alternative.$q$, $q$Privacy-focused individual users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$Cross-platform household or small team$q$, $q$Families or small teams share a single KDBX vault synced through Dropbox or Google Drive and access it from AuthPass on any device.$q$, $q$Small teams and households$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$overview$q$, $q$What Is AuthPass$q$, 2, ARRAY[$q$AuthPass is a free, open-source password manager built with Google's Flutter framework, which lets it run natively across Windows, macOS, Linux, Android, iOS, and the web from a single codebase. It was first released around September 2019 by Herbert Poul, a freelance developer based in Austria, and has since been maintained with help from open-source contributors.$q$, $q$The defining characteristic of AuthPass is that it works directly with KeePass-format database files, specifically KDBX 3 and KDBX 4. This means users are not locked into a proprietary vault format controlled by a single vendor; the same encrypted database file can be opened in AuthPass, KeePassXC, or other KeePass-compatible clients.$q$, $q$The project's source code is publicly available on GitHub under the GPL-3.0 license, and the app is distributed through the App Store, Google Play, and direct downloads for desktop platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$AuthPass loads and decrypts KDBX files using a master password and, optionally, a key file for an added layer of protection. Once unlocked, the app can store the master password in the device's secure keystore or keychain and let users unlock the vault afterward with a fingerprint or face scan.$q$, $q$Because AuthPass does not run its own proprietary sync service by default, it integrates with existing cloud storage providers, including Google Drive, Dropbox, and WebDAV-compatible services such as Nextcloud and ownCloud, so vaults stay synchronized across devices.$q$, $q$Other features include password generation, organization of entries into groups and tags, attachment support inherited from the KDBX format, and a consistent interface across desktop, mobile, and web so users have the same experience regardless of platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$AuthPass itself is free and open-source software with no license fee, subscription, or paid tier for the core app; anyone can download the source from GitHub and build or run it without payment.$q$, $q$There are no publicly listed pricing plans because AuthPass does not operate a commercial SaaS pricing model in the way closed-source competitors do; its sustainability instead comes from voluntary community contributions and the goodwill of its maintainers.$q$, $q$Users who want cloud sync typically bring their own storage account (Google Drive, Dropbox, or a WebDAV server), which may carry its own separate cost from the storage provider, but this is unrelated to AuthPass's own pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb5c1462-f100-411d-80a6-5e607484818f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Resource-based authorization$q$, $q$Grants permissions scoped to individual resources or records, not just broad application roles.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Unified authentication and authorization$q$, $q$Combines user login flows with access control decisions in a single API.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Enterprise SSO connections$q$, $q$Supports unlimited SAML, OAuth, and OIDC single sign-on connections.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Social login and machine tokens$q$, $q$Supports social identity providers as well as machine-to-machine authentication tokens.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Multi-language SDKs$q$, $q$Provides client libraries and documentation across a wide range of programming languages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$High availability$q$, $q$Advertises a 99.995 percent availability SLA for production workloads.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Enterprise invitation flows$q$, $q$Supports built-in sign-up and invitation workflows for onboarding organizational users.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Pay-per-call pricing$q$, $q$Bills only for actual authentication and authorization calls with no feature-gated tiers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Transparent, single pay-per-call pricing model with no feature-gated tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Fine-grained, resource-based authorization built in rather than bolted on$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Free allotment of 1,000 calls per month for small projects$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Unlimited SSO connections included at every usage level$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Simple integration model for teams that need both authentication and authorization$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Smaller, independently run company compared to major CIAM vendors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Limited public information on company size, funding, and long-term roadmap$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Usage-based pricing can be harder to forecast at very high call volumes than flat tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Smaller partner and integration ecosystem than Auth0 or Okta$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$What does Authress do$q$, $q$Authress provides a combined authentication and authorization API, handling both user login and fine-grained, resource-based access control decisions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$How is Authress priced$q$, $q$Authress uses pay-per-call pricing at 0.0012 US dollars per billable API call, with the first 1,000 calls each month free.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Who founded Authress$q$, $q$According to public company records, Authress was founded in 2018 by Dorota Parad and is based in Winterthur, Switzerland, operated by Rhosys AG.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Is Authress an Auth0 alternative$q$, $q$Yes, Authress is commonly compared to Auth0 as an authentication and authorization alternative, with a stronger emphasis on fine-grained authorization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Does Authress support single sign-on$q$, $q$Yes, Authress supports unlimited SAML, OAuth, and OIDC single sign-on connections on every plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Does Authress have a free tier$q$, $q$Yes, the first 1,000 billable API calls each month are free before usage-based billing applies.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$What is resource-based authorization$q$, $q$Resource-based authorization assigns permissions to specific resources or records rather than only broad, application-wide roles, allowing more precise access control.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$SaaS app needing granular permissions$q$, $q$Multi-tenant SaaS products use Authress to assign per-resource permissions so customers can control exactly what their own users can access.$q$, $q$SaaS engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Startup replacing custom auth code$q$, $q$Early-stage companies use Authress instead of building and maintaining their own authentication and permission logic in-house.$q$, $q$Startup development teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Enterprise integration with existing identity providers$q$, $q$Organizations connect their existing SAML or OIDC identity providers to Authress to centralize access control across multiple applications.$q$, $q$Enterprise IT and platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$Pay-per-call$q$, $q$$0.0012 per billable API call$q$, $q$usage-based, billed monthly$q$, NULL, $q$["First 1,000 calls per month free","Unlimited SSO connections","Unlimited social login","Fine-grained resource-based authorization","99.995 percent availability SLA"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$overview$q$, $q$What Is Authress$q$, 2, ARRAY[$q$Authress is a cloud-based API that provides both authentication and authorization for applications, aimed specifically at developers who need fine-grained control over what authenticated users are permitted to do, not just who they are. It is operated by Rhosys AG and, per public company databases, was founded in 2018 by Dorota Parad, with the company based in Winterthur, Switzerland.$q$, $q$Unlike identity providers that treat authorization as a secondary, role-based add-on, Authress is built around resource-based access control from the start, letting teams assign permissions down to individual records or objects rather than only broad application-wide roles.$q$, $q$Authress positions itself as an unfunded, independently operated alternative to larger CIAM vendors, and it emphasizes a single, transparent pay-per-call pricing model rather than tiered plans that gate features behind higher-priced tiers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Authress issues JSON Web Tokens (JWTs) for authenticated sessions and supports unlimited single sign-on connections across SAML, OAuth, and OIDC, plus social login and machine-to-machine tokens for service-to-service authentication.$q$, $q$Its authorization layer supports granular, resource-based permission checks, enterprise sign-up and invitation flows, and multi-language SDK support (the company references support across 26-plus languages for its client libraries and documentation).$q$, $q$Operationally, Authress advertises a 99.995 percent availability SLA and encrypts data both in transit and at rest, targeting production applications that need reliable, low-latency access decisions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Authress uses a single usage-based pricing model rather than multiple named plans: customers pay 0.0012 US dollars per billable API call, with only actual authentication and authorization calls counted toward billing.$q$, $q$The first 1,000 billable calls each month are free, which lets small projects and prototypes run at no cost before usage-based billing kicks in.$q$, $q$The company describes this as having no enterprise tax, meaning every customer, regardless of size or spend, gets access to the same full feature set, including SSO, social login, and fine-grained authorization, without needing to upgrade to a higher tier to unlock them.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ce7d7abb-965e-47fa-a6cd-0327c7df9079', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$TOTP code generation$q$, $q$Generates standard time-based one-time passcodes compatible with most services that support 2FA apps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Push-based authentication$q$, $q$Supports one-tap push approval for login requests on services that integrate with Authy.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Encrypted cloud backup$q$, $q$Backs up 2FA tokens in encrypted form so they can be restored on a new device.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Multi-device sync$q$, $q$Synchronizes tokens across multiple phones and tablets tied to the same account.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$PIN and biometric app lock$q$, $q$Protects the app itself with a PIN code or device biometrics.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$QR code setup$q$, $q$Adds new accounts by scanning standard QR codes presented during 2FA setup.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Free to use for consumers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Encrypted backup and multi-device sync, unlike many bare-bones 2FA apps$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Backed by Twilio, a large, publicly traded communications company$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Widely supported by major websites and services for 2FA setup$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Push-approval option in addition to standard TOTP codes$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Desktop apps were permanently discontinued in March 2024$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Reduced investment and unclear long-term roadmap for the mobile app$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$No official built-in export feature, making migration to another app difficult$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Requires a phone number and cloud backup, which some privacy-focused users avoid$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Twilio is steering developer efforts toward its separate Verify API rather than the legacy Authy API$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Is Authy still supported in 2026$q$, $q$The Authy mobile app remains available and functional, but Twilio discontinued the desktop apps in March 2024 and has visibly reduced investment in the consumer product, so users should verify current status directly with Twilio before relying on it long term.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Why did Authy shut down its desktop app$q$, $q$Twilio stated it wanted to concentrate development resources on higher-demand areas of its business, and ended support for the Windows, macOS, and Linux desktop apps on March 19, 2024.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Who owns Authy$q$, $q$Authy is owned by Twilio, which acquired the company in February 2015 for an undisclosed amount.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Is Authy free$q$, $q$Yes, the Authy mobile app is free for consumers to download and use for two-factor authentication.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Can I export my Authy tokens$q$, $q$Authy has historically lacked an official export feature, which makes migrating to a different 2FA app a manual process of disabling and re-enrolling each account.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$What are good Authy alternatives$q$, $q$Commonly recommended alternatives include Aegis, Ente Auth, 2FAS, and Microsoft Authenticator, several of which offer open-source code or easier data export.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Does Authy still work on desktop$q$, $q$No, Twilio ended support for Authy's Windows, macOS, and Linux desktop apps in March 2024; the product is now mobile-only.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Is Authy the same as Twilio Verify$q$, $q$No, Authy is the original consumer 2FA app and developer API Twilio acquired in 2015, while Twilio Verify is a newer, separate API that Twilio now recommends to developers for building authentication into their own products.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Consumer securing personal accounts$q$, $q$Individuals use the free Authy app to generate 2FA codes for services like exchanges, email, and social media accounts.$q$, $q$General consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$User migrating from Authy desktop$q$, $q$Former desktop app users manually re-enroll their accounts on the mobile-only app following the 2024 desktop shutdown.$q$, $q$Existing Authy users affected by the desktop EOL$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Developer evaluating 2FA options$q$, $q$Developers researching two-factor authentication for their own products compare the legacy Authy API against Twilio's newer Verify API before choosing an integration path.$q$, $q$Software developers and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$Authy App$q$, $q$Free$q$, $q$free, no subscription$q$, NULL, $q$["TOTP code generation","Push authentication","Encrypted cloud backup","Multi-device sync"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$overview$q$, $q$What Is Authy$q$, 2, ARRAY[$q$Authy is a two-factor authentication (2FA) mobile app that generates time-based one-time passcodes and supports push-notification-based login approval for online accounts. It was founded around 2011 to 2012, with early roots reportedly in Colombia before the company moved to California, and it grew with seed backing that included Y Combinator before being acquired by Twilio in February 2015 for an undisclosed sum.$q$, $q$Historically, Authy differentiated itself from competitors like Google Authenticator through encrypted cloud backup and multi-device synchronization, letting users recover or transfer their 2FA tokens across phones without losing access to accounts.$q$, $q$Since the Twilio acquisition, Authy has functioned as both a free consumer app and the branding for Twilio's underlying developer authentication API, though Twilio has since encouraged business customers to adopt its newer Verify API instead of the original Authy API for new integrations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$current-status$q$, $q$Current Status: Desktop Shutdown and Reduced Investment$q$, 2, ARRAY[$q$Twilio discontinued the Authy desktop applications for Windows, macOS, and Linux, with the official end-of-life date set for March 19, 2024. Desktop users were logged out and instructed to migrate all of their 2FA tokens to the mobile-only app, a process complicated by Authy's lack of a built-in export feature.$q$, $q$Coverage of the shutdown indicates Twilio made the decision to concentrate development resources on higher-demand areas of its business, which several industry outlets have interpreted as a broader deprioritization of the consumer-facing Authy product in favor of Twilio's enterprise-focused Verify API.$q$, $q$Twilio has stated it intends to keep the Authy mobile apps available for existing users and as a consumer option, and as of this research the mobile apps remain downloadable and functional, but there has been no confirmed public commitment to ongoing feature development. Readers evaluating Authy today should check Twilio's current changelog and app store listings directly, since the product's investment level has visibly declined and its long-term roadmap has not been clearly reaffirmed.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1766994-68c6-4c8b-afda-889f3aaad6f4', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The Authy mobile app is free for consumers and always has been; there is no subscription or paid tier for end users generating 2FA codes.$q$, $q$Twilio separately charges businesses for the developer-facing side of two-factor authentication through its Verify API, which is usage-based and billed per verification, but this is distinct from the free consumer Authy app.$q$, $q$Because Authy itself has no consumer pricing plans, there is no public pricing_plans structure to list beyond noting the app is free to download and use.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$AutoCAD 2D/3D drafting$q$, $q$General-purpose computer-aided design software used across architecture, engineering, and manufacturing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Revit building information modeling$q$, $q$BIM software purpose-built for architecture, structural, and MEP building design and coordination.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Fusion CAD/CAM/simulation$q$, $q$Cloud-connected platform combining mechanical design, manufacturing, and simulation tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Maya and 3ds Max 3D animation$q$, $q$Industry-standard tools for 3D modeling, animation, and visual effects in film, TV, and games.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Civil 3D infrastructure design$q$, $q$Specialized tools for civil engineering, grading, and infrastructure project design.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Autodesk Construction Cloud$q$, $q$Platform connecting design and construction teams around shared project data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Cloud collaboration$q$, $q$Cloud-based file sharing and real-time collaboration across most modern Autodesk products.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Educational licensing$q$, $q$Free access to most Autodesk software for verified students and educators.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Industry-standard tools with deep feature sets across multiple design disciplines$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Broad ecosystem of third-party plugins, training, and certified professionals$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Free educational licenses lower the barrier for students to learn on real tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Regularly updated with cloud collaboration and simulation capabilities$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Bundled collections can reduce per-product cost for teams needing multiple tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Subscription costs are high compared to some newer competitors and open-source alternatives$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Mandatory subscription model since discontinuing perpetual licenses has drawn criticism$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Steep learning curve for full-featured products like Revit and Maya$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Overlapping products across the portfolio can make purchasing decisions confusing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Frequent price increases and licensing changes over the years$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$What does Autodesk make$q$, $q$Autodesk makes design and engineering software including AutoCAD, Revit, Maya, 3ds Max, Civil 3D, and Fusion, used in architecture, engineering, construction, manufacturing, and media.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$When was Autodesk founded$q$, $q$Autodesk was founded in April 1982 by John Walker, Daniel Drake, and a group of other programmers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Where is Autodesk headquartered$q$, $q$Autodesk is headquartered in San Francisco, California, having moved there from San Rafael, California, in 2022.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Is Autodesk software subscription-based$q$, $q$Yes, Autodesk sells nearly all of its products by monthly, annual, or multi-year subscription rather than perpetual license.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Is there a free version of Autodesk software$q$, $q$Fusion offers a free tier for personal, non-commercial use, and most Autodesk products are available free to verified students and educators.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$What is the difference between AutoCAD and Revit$q$, $q$AutoCAD is general-purpose 2D and 3D drafting software, while Revit is purpose-built for building information modeling (BIM) in architecture and construction.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Is Autodesk a public company$q$, $q$Yes, Autodesk has been publicly traded since 1985 and trades on NASDAQ under the ticker ADSK.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Who are Autodesk's main competitors$q$, $q$Depending on the product line, competitors include Dassault Systemes (SolidWorks, CATIA), Bentley Systems, Trimble (SketchUp), PTC, and Blender as a free alternative for 3D animation.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Architecture firm designing a building$q$, $q$Architecture and engineering firms use Revit and the AEC Collection to model buildings, coordinate disciplines, and generate construction documents.$q$, $q$Architects, structural, and MEP engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Manufacturer developing a physical product$q$, $q$Product design and manufacturing teams use Fusion to design, simulate, and generate CNC toolpaths for physical parts.$q$, $q$Mechanical engineers and manufacturers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Studio producing 3D animation or VFX$q$, $q$Animation and visual effects studios use Maya and 3ds Max to model, rig, and animate characters and environments for film, TV, and games.$q$, $q$3D artists and animation studios$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Fusion (personal use)$q$, $q$Free$q$, $q$free$q$, NULL, $q$["Limited commercial restrictions","Core CAD/CAM/simulation tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Fusion (subscription)$q$, $q$Approx. $680/year (approx. $85/month)$q$, $q$annual or monthly$q$, NULL, $q$["Full CAD/CAM/simulation feature set","Cloud collaboration","Commercial use"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$Revit (single user)$q$, $q$Approx. $2,915/year$q$, $q$annual$q$, NULL, $q$["Building information modeling","Structural and MEP design tools","Cloud rendering"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$AEC Collection$q$, $q$Approx. $3,375-$3,795/year$q$, $q$annual$q$, NULL, $q$["Revit, AutoCAD, Civil 3D, Navisworks and more bundled","Discount versus buying products individually"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$overview$q$, $q$What Is Autodesk$q$, 2, ARRAY[$q$Autodesk is a publicly traded American software company that builds design and engineering tools used across architecture, engineering, construction, product manufacturing, and media and entertainment. Rather than a single application, Autodesk is best understood as a portfolio company whose products, including AutoCAD, Revit, Maya, 3ds Max, Civil 3D, and Fusion, each serve different professional design workflows.$q$, $q$The company was founded in April 1982 by John Walker, Daniel Drake, and a group of other programmers, and it built its early business around AutoCAD, one of the first computer-aided design programs available on personal computers. Autodesk has been publicly traded since 1985 and trades on NASDAQ under the ticker ADSK.$q$, $q$Autodesk's headquarters moved from San Rafael, California, where it had been based since 1994, to San Francisco in 2022. The company today serves millions of professional and student users worldwide through a mix of individual subscriptions, multi-product collections, and large enterprise agreements.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$key-features$q$, $q$Key Products and Features$q$, 2, ARRAY[$q$AutoCAD remains Autodesk's flagship general-purpose drafting tool for 2D and 3D design across industries, while Revit focuses specifically on building information modeling (BIM) for architecture, structural, and MEP (mechanical, electrical, plumbing) engineering teams designing buildings.$q$, $q$For manufacturing and product design, Fusion combines CAD, computer-aided manufacturing (CAM), and simulation in a cloud-connected platform, while Maya and 3ds Max serve 3D animation, modeling, and visual effects work common in film, television, and game development.$q$, $q$Autodesk also offers Civil 3D for civil engineering and infrastructure design, Navisworks for construction project review and clash detection, and Autodesk Construction Cloud, a broader platform for coordinating design and construction data across project teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11674814-c70f-44c9-ba68-d6bf1db1e289', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Autodesk sells almost all of its products by subscription, typically available as monthly, annual, or three-year commitments, with longer terms offering a lower effective monthly cost. Pricing varies significantly by product and industry collection.$q$, $q$As an example, a single named-user Revit subscription runs approximately 2,915 US dollars per year (roughly 380 dollars per month), while the broader AEC Collection, which bundles Revit with AutoCAD, Civil 3D, Navisworks, and other tools, runs approximately 3,375 to 3,795 dollars per year depending on the source and current promotions. Fusion is priced separately, with paid subscriptions around 680 dollars per year, alongside a free tier for personal, non-commercial use with reduced functionality.$q$, $q$Because pricing changes periodically and varies by region, product edition, and any active promotions, prospective buyers should confirm current prices directly on Autodesk's official pricing pages before purchasing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$Real-time AI translation$q$, $q$Automatically translates UI text into over 100 languages without manual translation file management.$q$, 0);
