INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$Character-based pricing can add unpredictable costs at high translation volumes$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$What is AutoLocalise used for$q$, $q$AutoLocalise is used by developers to add real-time, AI-powered translation to web and mobile applications without managing traditional translation files.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$How much does AutoLocalise cost$q$, $q$AutoLocalise has a free tier with 10,000 characters per month, and a Pro plan starting at nine dollars per month for 250,000 characters.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$What frameworks does AutoLocalise support$q$, $q$AutoLocalise supports React, Next.js, React Native, Expo, and Python-based applications.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$Does AutoLocalise require translation files$q$, $q$No, AutoLocalise is designed to eliminate the need for traditional translation files by automatically extracting and translating UI text through its SDK.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$How many languages does AutoLocalise support$q$, $q$AutoLocalise advertises support for translating into over 100 languages.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$Is AutoLocalise a good alternative to Lokalise or Crowdin$q$, $q$AutoLocalise is often marketed as a lower-cost alternative to Lokalise and Crowdin for teams with moderate translation needs, though it offers less mature translation management workflows.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$Does AutoLocalise work offline$q$, $q$AutoLocalise caches translations locally on the client, which supports offline availability of previously translated content.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$Startup launching an app internationally$q$, $q$Early-stage teams use AutoLocalise to quickly add multi-language support without hiring a dedicated localization team.$q$, $q$Startup engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$Team replacing an expensive localization platform$q$, $q$Companies with growing translation costs on platforms like Lokalise or Crowdin migrate to AutoLocalise to reduce monthly spend.$q$, $q$Product and engineering teams with existing localization tools$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$Developer adding translations without file management$q$, $q$Individual developers use AutoLocalise's SDK to translate an app's interface without maintaining separate translation files per language.$q$, $q$Independent developers and small teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["10,000 characters per month","1 project","Standard support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$Pro$q$, $q$$9/month$q$, $q$monthly$q$, NULL, $q$["250,000 characters per month","Unlimited projects","Priority support","Additional character bundles available"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$overview$q$, $q$What Is AutoLocalise$q$, 2, ARRAY[$q$AutoLocalise is a localization platform that uses AI to translate application and website text in real time, aiming to remove the traditional overhead of managing translation files and localization workflows. Instead of exporting strings to translation files and re-importing them after human translation, developers install a lightweight SDK that automatically detects and translates UI text as users interact with the app.$q$, $q$The platform supports popular frameworks including React, Next.js, React Native, Expo, and Python-based applications, and it promises translation into over 100 languages with updates that apply instantly, without requiring a new app build or deployment.$q$, $q$AutoLocalise appears to be a small, independently operated company; specific details about its founding year, funding history, and headquarters are not publicly confirmed in available sources, so those details should be verified directly with the company before being treated as fact.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of AutoLocalise's product is AI-powered translation that automatically extracts text from an application's interface and translates it with context awareness, improving over time as users make manual corrections to specific translations.$q$, $q$Translations update in real time without requiring developers to rebuild or redeploy their application, and the SDK caches translations locally on the client for fast performance and to support offline use.$q$, $q$Additional platform features include usage analytics for tracking translation activity and performance, and the ability to share and reuse translation projects across multiple applications within the same account.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e65336ed-2fb0-413b-92ae-f4002c55115f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$AutoLocalise offers a free tier that includes 10,000 translated characters per month and one project, suitable for testing the product or very small applications.$q$, $q$The Pro plan costs nine dollars per month and raises the limit to 250,000 characters per month with unlimited projects and priority support, positioning AutoLocalise significantly below the cost of many established localization platforms for teams with moderate translation volume.$q$, $q$Beyond the included character allowance, AutoLocalise charges additional usage fees, roughly one dollar per 30,000 extra characters, along with a per-seat charge of about two dollars per month for each additional team member added to an account.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Visual journey builder$q$, $q$Drag-and-drop canvas for designing multi-step marketing automation workflows (legacy Autopilot feature, continued in Ortto).$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Email marketing automation$q$, $q$Automated email sends triggered by customer behavior and journey logic.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Lead scoring and nurturing$q$, $q$Rules-based scoring to prioritize and automatically nurture leads through a funnel.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$CRM and app integrations$q$, $q$Connected to common CRM and marketing tools for syncing contact and activity data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Behavioral triggers$q$, $q$Journeys could be triggered by website, email, or product usage behavior.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Reporting and analytics$q$, $q$Campaign and journey performance reporting, expanded significantly under the Ortto rebuild.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Original Autopilot canvas UI was praised for being intuitive and visually clear$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Underlying technology and customer relationships carried forward into Ortto rather than being shut down$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Rebrand added broader customer data and analytics capabilities beyond the original tool$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Established company history dating back to the early 2010s$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Autopilot as a brand and standalone product no longer exists$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Legacy marketing materials and reviews referencing Autopilot may be outdated$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Migration to Ortto's rebuilt platform may have changed pricing and features from what long-time Autopilot users expected$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Ownership history involving any Aurea or ESW Capital connection could not be independently confirmed from available sources$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Is Autopilot marketing automation still available$q$, $q$No, Autopilot was fully rebranded as Ortto in March 2022, and the autopilothq.com domain now redirects to Ortto's website.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$What happened to Autopilot$q$, $q$Autopilot's company rebuilt its product with expanded customer data and analytics features starting in 2021 and completed a full rebrand to Ortto in March 2022.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Was Autopilot acquired by Aurea or ESW Capital$q$, $q$This research did not find a verifiable public source confirming an acquisition of Autopilot by Aurea or ESW Capital; this claim should be independently verified before being treated as fact.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Where can I find Autopilot's current pricing$q$, $q$Because Autopilot no longer exists as an independently branded product, current pricing is published by Ortto, its successor platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Is Ortto the same company as Autopilot$q$, $q$Yes, Ortto is the rebranded continuation of Autopilot, using the same underlying technology and customer base under an expanded product vision.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$When was Autopilot founded$q$, $q$Autopilot was founded around 2011, though exact incorporation details are not comprehensively documented in public sources.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Should I sign up for Autopilot today$q$, $q$No, prospective buyers should evaluate Ortto directly, since Autopilot is no longer sold or supported under its original name.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Historical reference for legacy Autopilot customers$q$, $q$Existing customers researching what happened to their Autopilot account are directed to Ortto, which now hosts the same underlying platform.$q$, $q$Former Autopilot customers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Buyer researching marketing automation history$q$, $q$Buyers comparing marketing automation vendors may encounter Autopilot in reviews or comparisons and need to understand it now operates as Ortto.$q$, $q$Marketing software buyers doing vendor research$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$Analyst tracking martech consolidation$q$, $q$Industry analysts referencing Autopilot as a case study in marketing automation platform rebrands and consolidation.$q$, $q$Industry analysts and researchers$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$overview$q$, $q$What Was Autopilot$q$, 2, ARRAY[$q$Autopilot was a visual marketing automation platform known for its drag-and-drop canvas interface, which let marketers build multi-step customer journeys, automated emails, and lead-nurturing sequences without writing code. The company was founded around 2011 and grew a customer base among small and mid-sized marketing teams looking for an alternative to more complex enterprise marketing automation suites.$q$, $q$In 2021, the company undertook a significant product rebuild, expanding beyond journey-based marketing automation into broader customer data management and analytics, releasing the new platform in beta that year.$q$, $q$In March 2022, the company completed a full rebrand from Autopilot to Ortto, describing the change as a natural evolution of the product and company rather than an acquisition-driven shutdown; the autopilothq.com domain now redirects visitors to Ortto's website.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$ownership-history$q$, $q$Ownership and Rebrand History$q$, 2, ARRAY[$q$Autopilot's own public materials attribute the Ortto rebrand to organic company growth and an expanded product vision, positioning Ortto as encompassing customer data, messaging, and analytics in a single platform rather than just the original journey-builder tool.$q$, $q$Some third-party sources reference Aurea and its affiliate ESW Capital as a firm known for acquiring and consolidating enterprise software brands, including companies like Jive Software. However, available public sources for this research did not surface a documented, verifiable connection between Autopilot or Ortto and Aurea or ESW Capital, so this should not be treated as confirmed; readers who have seen this claim elsewhere should independently verify it against primary sources such as SEC filings, press releases, or Ortto's own corporate disclosures.$q$, $q$What can be confirmed is that Autopilot is no longer sold or marketed under its original name. The product, customers, and underlying technology continued forward as Ortto, meaning any evaluation of 'Autopilot' today should really be an evaluation of Ortto's current offering, pricing, and roadmap.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a7e05556-33fe-45dc-becd-a33082027c3f', $q$pricing$q$, $q$Pricing Today$q$, 2, ARRAY[$q$Because Autopilot has been fully retired as a brand since March 2022, there is no current, independently priced Autopilot product; all pricing today is set and published by Ortto.$q$, $q$Historical Autopilot pricing information is not reliable for purchasing decisions since the underlying product, plans, and pricing structure changed substantially with the Ortto rebuild and rebrand.$q$, $q$Prospective buyers interested in the capabilities Autopilot originally offered should request current pricing directly from Ortto rather than relying on legacy Autopilot marketing pages, which may no longer reflect the live product.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Multi-site rental listing$q$, $q$Distributes property listings to roughly 19 rental listing sites from a single dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Tenant screening$q$, $q$Provides credit, criminal background, and eviction reports powered by TransUnion.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$State-specific digital leases$q$, $q$Generates state- and city-specific lease agreements with e-signature support.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Online rent collection$q$, $q$Lets tenants pay rent online via bank transfer or card, with optional FastPay payout speed.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Maintenance request tracking$q$, $q$Tenants submit and track maintenance requests through a 24/7 online portal.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Financial tracking tools$q$, $q$Helps landlords track rental income and expenses within the platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Branded property website$q$, $q$Available on the paid plan, lets landlords create a custom-branded marketing page for their rentals.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Core plan is free, covering listing, screening, leasing, and rent collection$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Backed by Realtor.com's large rental listing network and audience$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Tenant screening powered by an established credit bureau, TransUnion$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$State- and city-specific lease templates reduce legal guesswork for landlords$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Purpose-built for small-scale independent landlords rather than large portfolios$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Card payment processing carries a 3.5 percent fee on both plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Free plan charges a per-transfer fee that only the paid plan waives$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Best suited to small portfolios (one to fifty units) rather than large-scale property management$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Some advanced features are gated behind the paid Unlimited Plus tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Domain and branding transition from avail.co to avail.com may cause temporary confusion for existing users$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Is Avail free for landlords$q$, $q$Yes, Avail's Unlimited plan is free per unit and includes listing, tenant screening, leases, rent collection, and maintenance tracking; a paid Unlimited Plus plan adds extra features for nine dollars per unit per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Who owns Avail$q$, $q$Avail is owned by Move, Inc., the operator of Realtor.com, which acquired it on December 15, 2020; Move is a subsidiary of News Corp.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Did Avail rebrand or merge into Realtor.com$q$, $q$Avail continues to operate under its own brand as 'Avail, by Realtor.com' rather than being fully merged or discontinued, though it moved its website from avail.co to avail.com in 2026.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$How many rental units can Avail handle$q$, $q$Avail is designed primarily for independent landlords managing between one and fifty rental units.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Does Avail screen tenants$q$, $q$Yes, Avail provides tenant screening reports, including credit, criminal background, and eviction history, powered by TransUnion.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$What is included in Avail Unlimited Plus$q$, $q$Unlimited Plus adds faster rent payouts through FastPay, waived ACH fees, customizable lease templates, a branded property website, and priority support for nine dollars per unit per month.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Is Avail the same company as Rentalutions$q$, $q$Yes, Avail began as Rentalutions, a Chicago-based startup founded around 2013, before rebranding to Avail.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$What fees does Avail charge for rent payments$q$, $q$Card payments carry a 3.5 percent fee on both plans; bank transfers cost $2.50 on the free plan and are free on the Unlimited Plus plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$First-time landlord listing a rental$q$, $q$New landlords use Avail's free plan to list a property across multiple rental sites and screen applicants without hiring a property manager.$q$, $q$First-time and small-scale landlords$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Landlord managing multiple properties$q$, $q$Landlords with several units use Avail's Unlimited Plus plan for faster payouts, branded listings, and priority support across their portfolio.$q$, $q$Landlords with multiple rental units$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Landlord needing state-compliant leases$q$, $q$Landlords in states with specific legal requirements use Avail's state- and city-specific lease templates to stay compliant.$q$, $q$Landlords in regulated rental markets$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Unlimited$q$, $q$$0/unit$q$, $q$free$q$, NULL, $q$["Listing distribution to about 19 sites","Tenant applications and screening","State-specific digital leases","Online rent collection","Maintenance request tracking","24/7 tenant portal"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$Unlimited Plus$q$, $q$$9/unit/month$q$, $q$monthly$q$, NULL, $q$["All Unlimited features","FastPay faster rent payouts","Waived ACH transfer fees","Customizable lease templates","Branded property website","Priority customer support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$overview$q$, $q$What Is Avail$q$, 2, ARRAY[$q$Avail is a property management platform designed for independent landlords, typically those managing between one and fifty rental units, who want professional tools for listing, screening, leasing, and rent collection without hiring a full-service property manager. The company began as Rentalutions, a Chicago-based startup founded around 2013, before rebranding to Avail.$q$, $q$On December 15, 2020, Move, Inc., the company behind Realtor.com and a subsidiary of News Corp, acquired Avail. Rather than folding Avail into Realtor.com's broader brand or discontinuing it, the acquisition kept Avail operating under its own name, now marketed as 'Avail, by Realtor.com,' reflecting its place inside the larger Realtor.com family of products while retaining a distinct identity aimed specifically at DIY landlords.$q$, $q$In 2026, Avail began transitioning its primary web domain from avail.co to avail.com to align more closely with the Realtor.com brand family; the legacy avail.co domain now redirects automatically to avail.com.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Avail lets landlords list rental properties across roughly 19 rental listing sites from a single dashboard, reducing the manual work of posting to multiple platforms individually.$q$, $q$For tenant screening, Avail partners with TransUnion to provide credit reports, criminal background checks, and eviction history as part of the applicant review process, and it offers state- and city-specific digital lease agreements that landlords can customize and send for e-signature.$q$, $q$Once a lease is signed, landlords can collect rent online, track maintenance requests submitted through a 24/7 tenant portal, and use built-in financial tracking and messaging tools to manage day-to-day communication with tenants.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69678cd0-36bc-465c-ad49-76349776fb26', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Avail's core Unlimited plan is free per unit and includes listing distribution, tenant applications and screening, state-specific leases, online rent collection, maintenance tracking, and tenant portal access.$q$, $q$The paid Unlimited Plus plan costs nine dollars per unit per month and adds faster rent payouts through FastPay, waived ACH transfer fees, customizable and clonable lease templates, a branded property marketing website, and priority customer support with faster response times.$q$, $q$Outside the core subscription, tenants may be charged separately for screening reports depending on location, and a 3.5 percent fee applies to card payments on both the free and paid plans; bank transfer fees are $2.50 on the free plan and waived on Unlimited Plus.$q$]::text[], 2);
